const { LinkedDefinitions } = require ('../../core/linked-csn')
const { readFileSync } = require('fs')
const YAML = require ('yaml')

module.exports = {
  read: (file) => YAML.parse (readFileSync(file,'utf-8'), { filename: file }),
  parse: YAML.parse,
  stringify: (x,o) => YAML.stringify (x, (_,v) => v instanceof LinkedDefinitions ? {...v} : v, o),
}
